const values = $.steps.readFinancialData.response.values || [];
let dataText = '';
let totalIncome = 0;
let totalExpenses = 0;
let categories = {};

values.forEach((row, i) => {
  if (i === 0) return;
  const date = row[0] || '';
  const category = row[1] || 'Uncategorized';
  const desc = row[2] || '';
  const amount = parseFloat(row[3]) || 0;
  const type = (row[4] || '').toLowerCase();

  if (type === 'income' || type === 'revenue') { totalIncome += amount; }
  else { totalExpenses += Math.abs(amount); }

  if (!categories[category]) categories[category] = 0;
  categories[category] += Math.abs(amount);

  dataText += date + ' | ' + category + ' | ' + desc + ' | ' + amount + ' | ' + type + '\n';
});

const netIncome = totalIncome - totalExpenses;
let catSummary = '';
Object.keys(categories).sort((a, b) => categories[b] - categories[a]).forEach(cat => {
  catSummary += cat + ': $' + categories[cat].toFixed(2) + '\n';
});

return {
  dataText: dataText.slice(0, 5000),
  totalIncome,
  totalExpenses,
  netIncome,
  catSummary,
  transactionCount: values.length - 1,
  categoryCount: Object.keys(categories).length
};

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { executiveSummary: raw, recommendations: [] }; }

const ai = $.steps.parseAI.output;
const d = $.steps.processFinancialData.output;
const company = $.input.companyName || 'Company';

let html = '<h1>' + (ai.reportTitle || 'Monthly Financial Report') + '</h1>';
html += '<p><strong>Period:</strong> ' + (ai.period || new Date().toISOString().split('T')[0]) + '</p>';
html += '<h2>Executive Summary</h2><p>' + (ai.executiveSummary || '') + '</p>';
html += '<h2>Financial Overview</h2>';
html += '<table border="1" cellpadding="8"><tr><th>Metric</th><th>Amount</th></tr>';
html += '<tr><td>Total Revenue</td><td>$' + d.totalIncome.toFixed(2) + '</td></tr>';
html += '<tr><td>Total Expenses</td><td>$' + d.totalExpenses.toFixed(2) + '</td></tr>';
html += '<tr><td><strong>Net Income</strong></td><td><strong>$' + d.netIncome.toFixed(2) + '</strong></td></tr></table>';

if (ai.expenseAnalysis && ai.expenseAnalysis.topCategories) {
  html += '<h2>Top Expense Categories</h2><ul>';
  ai.expenseAnalysis.topCategories.forEach(c => { html += '<li>' + c.name + ': $' + c.amount + ' (' + c.percentage + ')</li>'; });
  html += '</ul>';
}

if (ai.recommendations && ai.recommendations.length > 0) {
  html += '<h2>Recommendations</h2><ol>';
  ai.recommendations.forEach(r => { html += '<li>[' + r.priority + '] ' + r.action + '</li>'; });
  html += '</ol>';
}

html += '<h2>Outlook</h2><p>' + (ai.outlook || '') + '</p>';
html += '<hr><p><em>Generated on ' + new Date().toISOString().split('T')[0] + '</em></p>';

const subject = (ai.reportTitle || 'Monthly Financial Report') + ' - ' + new Date().toISOString().split('T')[0];
const slackText = 'Financial report sent: ' + company + ' | Revenue: $' + d.totalIncome.toFixed(2) + ' | Expenses: $' + d.totalExpenses.toFixed(2) + ' | Net: $' + d.netIncome.toFixed(2);
return { html, subject, slackText };
